Shader.cpp:

```cpp
#include "Shader.h"
#include <fstream>
#include <vector>
#include <iostream>

Shader::Shader()
	: device(VK_NULL_HANDLE), shaderModule(VK_NULL_HANDLE), stage(VK_SHADER_STAGE_VERTEX_BIT)
{
}

Shader::~Shader()
{
	Cleanup();
}

void Shader::LoadFromFile(const std::string& filename, VkDevice device, VkShaderStageFlagBits stage)
{
	this->device = device;
	this->stage = stage;

	// Read shader file into a buffer
	std::ifstream file(filename, std::ios::ate | std::ios::binary);

	if (file.is_open())
	{
		size_t fileSize = static_cast<size_t>(file.tellg());
		std::vector<char> buffer(fileSize);

		file.seekg(0);
		file.read(buffer.data(), fileSize);
		file.close();

		// Create shader module from the buffer
		VkShaderModuleCreateInfo shaderModuleCreateInfo {};
		shaderModuleCreateInfo.sType = VK_STRUCTURE_TYPE_SHADER_MODULE_CREATE_INFO;
		shaderModuleCreateInfo.codeSize = buffer.size();
		shaderModuleCreateInfo.pCode = reinterpret_cast<const uint32_t*>(buffer.data());

		if (vkCreateShaderModule(device, &shaderModuleCreateInfo, nullptr, &shaderModule) != VK_SUCCESS)
		{
			throw std::runtime_error("Failed to create shader module.");
		}
	}
	else
	{
		throw std::runtime_error("Failed to open shader file.");
	}
}

void Shader::Cleanup()
{
	if (shaderModule != VK_NULL_HANDLE)
	{
		vkDestroyShaderModule(device, shaderModule, nullptr);
		shaderModule = VK_NULL_HANDLE;
	}
}

VkPipelineShaderStageCreateInfo Shader::GetPipelineShaderStageCreateInfo() const
{
	VkPipelineShaderStageCreateInfo shaderStageCreateInfo {};
	shaderStageCreateInfo.sType = VK_STRUCTURE_TYPE_PIPELINE_SHADER_STAGE_CREATE_INFO;
	shaderStageCreateInfo.stage = stage;
	shaderStageCreateInfo.module = shaderModule;
	shaderStageCreateInfo.pName = "main";

	return shaderStageCreateInfo;
}
```

This Shader class loads a SPIR-V shader file from disk and creates a VkShaderModule with the loaded code. The Cleanup() method ensures the destruction of the created VkShaderModule. The GetPipelineShaderStageCreateInfo() method returns a VkPipelineShaderStageCreateInfo structure pre-populated with the shader information, which can then be used in the creation of a Vulkan pipeline.

